private void tdDebit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal pol = 0;
decimal actRecEggs = 0;

// --- Read values ---
if (GetCurrentColumnValue("POL") != null)
    pol = Convert.ToDecimal(GetCurrentColumnValue("POL"));

if (GetCurrentColumnValue("ActRecEggs") != null)
    actRecEggs = Convert.ToDecimal(GetCurrentColumnValue("ActRecEggs"));

// --- Equation ---
decimal percentage = 0;
if (pol != 0)
    percentage = (actRecEggs / pol) * 100m;


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.##"); // format with 2 decimals

}

