private void tdCredit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal pol = 0;
decimal rejEggs = 0;
decimal actRecEggs = 0;

// --- Read values ---
if (GetCurrentColumnValue("POL") != null)
    pol = Convert.ToDecimal(GetCurrentColumnValue("POL"));

if (GetCurrentColumnValue("RejEggs") != null)
    rejEggs = Convert.ToDecimal(GetCurrentColumnValue("RejEggs"));

if (GetCurrentColumnValue("ActRecEggs") != null)
    actRecEggs = Convert.ToDecimal(GetCurrentColumnValue("ActRecEggs"));

// --- Equation ---
decimal result = 0;
if (pol != 0)
    result = (rejEggs / pol) - (actRecEggs / pol);


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // up to 2 decimals

}

private void xrTableCell1_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal pol = 0;
