    ratio = actSetEggCum / pol;   // no *100 since your expression didn’t include %

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = ratio.ToString("0.##");   // 2 decimal places

}

private void xrTableCell17_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Declare values ---
decimal pol = 0;
decimal settedEggs = 0;
decimal estHatEggsBefore21days = 0;
decimal actChicks = 0;
decimal cullsChicks = 0;
decimal deadChicks = 0;

// --- Read values ---
if (GetCurrentColumnValue("POL") != null)
    pol = Convert.ToDecimal(GetCurrentColumnValue("POL"));

if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

if (GetCurrentColumnValue("EstHatEggsBefore21days") != null)
    estHatEggsBefore21days = Convert.ToDecimal(GetCurrentColumnValue("EstHatEggsBefore21days"));

if (GetCurrentColumnValue("ActChicks") != null)
    actChicks = Convert.ToDecimal(GetCurrentColumnValue("ActChicks"));

if (GetCurrentColumnValue("CullsChicks") != null)
    cullsChicks = Convert.ToDecimal(GetCurrentColumnValue("CullsChicks"));

if (GetCurrentColumnValue("DeadChicks") != null)
    deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"));

// --- Equation ---
decimal percentage = 0;

if (pol > 0)
{
    decimal hatchPerc = 0;
    if (settedEggs != 0)
        hatchPerc = ((actChicks + cullsChicks + deadChicks) / settedEggs) * 100m;

    percentage = (estHatEggsBefore21days * (hatchPerc / 100m)) / pol;

}

