private void xrTableCell21_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal settedEggs = 0;
decimal actChicks = 0;
decimal cullsChicks = 0;
decimal deadChicks = 0;
decimal stdHatchCum = 0;

// --- Read values ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

if (GetCurrentColumnValue("ActChicks") != null)
    actChicks = Convert.ToDecimal(GetCurrentColumnValue("ActChicks"));

if (GetCurrentColumnValue("CullsChicks") != null)
    cullsChicks = Convert.ToDecimal(GetCurrentColumnValue("CullsChicks"));

if (GetCurrentColumnValue("DeadChicks") != null)
    deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"));

if (GetCurrentColumnValue("StdHatchCum") != null)
    stdHatchCum = Convert.ToDecimal(GetCurrentColumnValue("StdHatchCum"));

// --- Equation ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = ((actChicks + cullsChicks + deadChicks) / settedEggs) * 100m - stdHatchCum;


// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.##");   // format with 2 decimals

}
